import{_ as t,o as i,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt3701.jpg",l="/images/lekt3702.jpg",o="/images/lekt3703.jpg",u="/images/lekt3704.jpg",s="/images/lekt3705.jpg",d="/images/lekt3706.jpg",h="/images/lekt3707.jpg",p="/images/lekt3708.jpg",m="/images/lekt3709.jpg",b="/images/lekt3710.jpg",c="/images/lekt3711.jpg",A=JSON.parse('{"title":"Lektion 37","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion37.md","filePath":"lektionen/lektion37.md"}'),g={name:"lektionen/lektion37.md"};function k(f,e,q,v,w,z){return i(),r("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-37" tabindex="-1">Lektion 37 <a class="header-anchor" href="#lektion-37" aria-label="Permalink to &quot;Lektion 37&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>37.1. Das Adverb (क्रियाविशेषनम्)</li><li>37.2. Adverbialer Gebrauch von Kasusformen <ul><li>37.2.1. Akkusativ (द्वितीया)</li><li>37.2.2. Instrumentalis (तृतीया)</li><li>37.2.3. Dativ (चतुर्थी)</li><li>37.2.4. Ablativ (पञ्चमी)</li><li>37.2.5. Genetiv (षष्ठी)</li><li>37.2.6. Lokativ (सप्तमी)</li></ul></li><li>37.3. Adverbialer Gebrauch nicht mehr gebräuchlicher Kasusfomen</li><li>37.4. Bildung von Adverbien mit Adverbialsuffixen</li><li>37.5. Adverbiale Komposita <ul><li>37.5.1. Komposita mit einem Adverb oder adverbial gebrauchtem Kasus als Hinterglied</li><li>37.5.2. Adverbial gebrauchte बहुव्रीहि</li><li>37.5.3. अव्ययीभाव-Komposita</li></ul></li><li>37.6. Syntaktisches</li><li>37.7. Indefinitpronomina</li><li>37.8. Der Fragesatz <ul><li>37.8.1. Wortfragen (Ergänzungsfragen)</li><li>37.8.2. Satzfragen</li></ul></li><li>37.9. Wortliste</li><li>37.10. Übung</li><li>37.11. Wiederholungsübung</li></ul><h2 id="_37-1-das-adverb-क्रियाविशेषनम्" tabindex="-1">37.1. Das Adverb (क्रियाविशेषनम्) <a class="header-anchor" href="#_37-1-das-adverb-क्रियाविशेषनम्" aria-label="Permalink to &quot;37.1. Das Adverb (क्रियाविशेषनम्)&quot;">​</a></h2><p>Adverbien werden im Sanskrit gebildet</p><ol><li>durch Kasusformen von Nomina und Pronomina</li><li>mit Hilfe besonderer Suffixe und Endungen</li></ol><p>Im ersten Fall ist die Grenze zwischen lebendigem Kasus und Adverb fließend. Hierzu gehören als Sonderfall die Adverbien, die erstarrte, alte Kasusformen sind, während in der Deklination andere Formen gebraucht werden bzw. die entsprechenden Nomina nicht mehr als Nomina gebraucht werden.</p><h2 id="_37-2-adverbialer-gebrauch-von-kasusformen" tabindex="-1">37.2. Adverbialer Gebrauch von Kasusformen <a class="header-anchor" href="#_37-2-adverbialer-gebrauch-von-kasusformen" aria-label="Permalink to &quot;37.2. Adverbialer Gebrauch von Kasusformen&quot;">​</a></h2><h3 id="_37-2-1-akkusativ-द्वितीया" tabindex="-1">37.2.1. Akkusativ (द्वितीया) <a class="header-anchor" href="#_37-2-1-akkusativ-द्वितीया" aria-label="Permalink to &quot;37.2.1. Akkusativ (द्वितीया)&quot;">​</a></h3><p>Der Akkusativ (द्वितीया) kann adverbial gebraucht werden auf die Fragen:</p><ul><li>in welcher Weise?</li><li>wie lange?</li><li>wohin?</li><li>u. ä.</li></ul><p>Adverbial gebraucht werden kann der Akkusativ:</p><ul><li>von Substantiven<br> Beispiele:<br> कामम् &quot;wunschgemäß, nach Wunsch&quot;<br> अर्थम् &quot;wegen&quot;</li><li>von Adjektiven im Neutrum<br> Beispiele:<br> सुखम् &quot;leicht, glücklich&quot;<br> नित्यम् &quot;stets&quot;<br> साधु &quot;richtig, gut&quot;</li><li>von Pronomina im Neutrum<br> Beispiele:<br> तद् &quot;dann, darum&quot;<br> यद् &quot;wenn, dass&quot;<br> एतद् &quot;so, hier, jetzt&quot;</li></ul><h3 id="_37-2-2-instrumentalis-तृतीया" tabindex="-1">37.2.2. Instrumentalis (तृतीया) <a class="header-anchor" href="#_37-2-2-instrumentalis-तृतीया" aria-label="Permalink to &quot;37.2.2. Instrumentalis (तृतीया)&quot;">​</a></h3><p>Der Instrumentalis (तृतीया) kann adverbial gebraucht werden auf die Fragen:</p><ul><li>wodurch?</li><li>womit?</li><li>u. ä.</li></ul><p>Adverbial gebraucht werden kann der Instrumentalis:</p><ul><li>von Substantiven<br> Beispiele:<br> अर्थेन &quot;wegen&quot;<br> क्षणेन &quot;im Augenblick, sofort&quot; (von क्षण m. &quot;Augenblick&quot;)</li><li>von Adjektiven, oft auch in der Pluralform<br> Beispiele:<br> दूरेण &quot;fern, aus der Ferne&quot; (zu दूर 3 &quot;fern, weit von&quot;)<br> उच्चैस् &quot;hoch, laut&quot; (zu उच्च 3 &quot;hoch, erhöht, laut, schrill (von Stimme)&quot;)</li></ul><h3 id="_37-2-3-dativ-चतुर्थी" tabindex="-1">37.2.3. Dativ (चतुर्थी) <a class="header-anchor" href="#_37-2-3-dativ-चतुर्थी" aria-label="Permalink to &quot;37.2.3. Dativ (चतुर्थी)&quot;">​</a></h3><p>Selten wird der Dativ (चतुर्थी) adverbial gebraucht auf die Fragen:</p><ul><li>zu welchem Zweck?</li><li>u. ä.</li></ul><p>Beispiel:</p><blockquote><p>अर्थाय &quot;zum Zweck von, um ... willen&quot;</p></blockquote><h3 id="_37-2-4-ablativ-पञ्चमी" tabindex="-1">37.2.4. Ablativ (पञ्चमी) <a class="header-anchor" href="#_37-2-4-ablativ-पञ्चमी" aria-label="Permalink to &quot;37.2.4. Ablativ (पञ्चमी)&quot;">​</a></h3><p>Der Ablativ (पञ्चमी) kann adverbial gebraucht werden auf die Fragen:</p><ul><li>warum?</li><li>aufgrund wessen?</li><li>woher?</li><li>u. ä.</li></ul><p>Adverbial gebraucht werden kann der Ablativ:</p><ul><li>von Substantiven<br> z.B. बलात् &quot;gewaltsam, mit Gewalt&quot;</li><li>von Adjektiven<br> z.B. दूरात् &quot;von fern&quot;</li><li>von Pronomina<br> Beispiele:<br> कस्मात् &quot;warum&quot;<br> अकस्मात् &quot;unerwartet&quot;</li></ul><h3 id="_37-2-5-genetiv-षष्ठी" tabindex="-1">37.2.5. Genetiv (षष्ठी) <a class="header-anchor" href="#_37-2-5-genetiv-षष्ठी" aria-label="Permalink to &quot;37.2.5. Genetiv (षष्ठी)&quot;">​</a></h3><p>Selten wird der Genetiv (षष्ठी) adverbial gebraucht auf die Frage &quot;nach wie langer Zeit?&quot;</p><p>z.B. चिरस्य &quot;nach langer Zeit&quot; (zu चिर 3 &quot;lang (Zeit)&quot;</p><h3 id="_37-2-6-lokativ-सप्तमी" tabindex="-1">37.2.6. Lokativ (सप्तमी) <a class="header-anchor" href="#_37-2-6-lokativ-सप्तमी" aria-label="Permalink to &quot;37.2.6. Lokativ (सप्तमी)&quot;">​</a></h3><p>Der Lokativ (सप्तमी) kann adverbial gebraucht werden auf die Fragen:</p><ul><li>wo?</li><li>unter welchen Umständen?</li><li>u. ä.</li></ul><p>Beispiele:</p><blockquote><p>-अर्थे &quot;wegen&quot;<br> -कृते &quot;um willen&quot;<br> दूरे &quot;fern&quot;</p></blockquote><h2 id="_37-3-adverbialer-gebrauch-nicht-mehr-gebrauchlicher-kasusfomen" tabindex="-1">37.3. Adverbialer Gebrauch nicht mehr gebräuchlicher Kasusfomen <a class="header-anchor" href="#_37-3-adverbialer-gebrauch-nicht-mehr-gebrauchlicher-kasusfomen" aria-label="Permalink to &quot;37.3. Adverbialer Gebrauch nicht mehr gebräuchlicher Kasusfomen&quot;">​</a></h2><p>Beispiele:</p><blockquote><p>जातु &quot;überhaupt&quot; (ursprünglich &quot;von Geburt, von Natur&quot;, Akk.sg.n. zu जातु &lt;nicht mehr als Nomen gebräuchlich&gt;)</p><p>तूष्णीम् &quot;schweigend&quot; (Akk.sg. zu einem nicht mehr gebräuchlichen तूष्णी f. &quot;Schweigen&quot;)</p><p>एवम् &quot;so&quot; (zu einem sonst verloren gegangenen Pronominalstamm एव &quot;ein, einzig&quot;)</p></blockquote><h2 id="_37-4-bildung-von-adverbien-mit-adverbialsuffixen" tabindex="-1">37.4. Bildung von Adverbien mit Adverbialsuffixen <a class="header-anchor" href="#_37-4-bildung-von-adverbien-mit-adverbialsuffixen" aria-label="Permalink to &quot;37.4. Bildung von Adverbien mit Adverbialsuffixen&quot;">​</a></h2><p>Von den Pronominalstämmen तद्, इदम् bzw. अ-, यद्, किम् bzw. कु kann man mit den Adverbialsuffixen</p><ul><li>-तस् (Ablativ)</li><li>-त्र (Lokativ)</li><li>-था (Art und Weise)</li><li>-थम् (Art und Weise)</li><li>-दा (Zeit)</li></ul><p>entsprechende Pronominaladverbien ableiten.</p><table tabindex="0"><thead><tr><th>Suffix</th><th>Pronominalstamm</th></tr></thead><tbody><tr><td></td><td>तद्</td></tr><tr><td>अ</td><td>यद्</td></tr><tr><td>कु</td><td></td></tr><tr><td>-तस्</td><td></td></tr><tr><td>Ablativ</td><td>ततस्</td></tr><tr><td>von da, darauf, deshalb</td><td>इतस्</td></tr><tr><td>अतस्</td><td></td></tr><tr><td>von hier, dieserhalb</td><td>यतस्</td></tr><tr><td>woher, wovon</td><td>कुतस्</td></tr><tr><td>woher?, weshalb?</td><td></td></tr><tr><td>-त्र</td><td></td></tr><tr><td>Lokativ</td><td>तत्र</td></tr><tr><td>da, dort</td><td>अत्र</td></tr><tr><td>hier</td><td>यत्र</td></tr><tr><td>wo</td><td>कुत्र</td></tr><tr><td>wo?</td><td></td></tr><tr><td>-था</td><td></td></tr><tr><td>Art und Weise</td><td>तथा</td></tr><tr><td>so</td><td></td></tr><tr><td>wie</td><td></td></tr><tr><td>-थम्</td><td></td></tr><tr><td>Art und Weise</td><td></td></tr><tr><td>wie?</td><td></td></tr><tr><td>-दा</td><td></td></tr><tr><td>Zeit</td><td>तदा</td></tr><tr><td>damals, dann</td><td></td></tr><tr><td>als</td><td>कदा</td></tr><tr><td>wann?</td><td></td></tr></tbody></table><p>Ein weiteres Frageadverb ist: क्व &quot;wo?&quot;</p><p><img src="'+n+'" alt=""><br> Abb.: क्व ?<br> [Bildquelle: Meanest Indian. -- <a href="http://www.flickr.com/photos/meanestindian/164113021/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/meanestindian/164113021/</a>. -- Zugriff am 2008-12-30. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p></p><table><tbody><tr><td colspan="2">**Weitere Adverbialsuffixe**</td></tr><tr><td>-वत्</td><td>**kann an beliebige Nomina angehängt werden, um auszudrücken &quot;nach Art von, gleich wie&quot;**** **z.B. पुत्रवत् &quot;wie ein(en) Sohn&quot;</td></tr><tr><td>-तस्</td><td>**an Nomina und Pronomina. Meist ablativische Bedeutung &quot;woher?&quot;, aber auch &quot;wo?&quot;, &quot;wohin?&quot;**z.B. आदितस् &quot;von Anfang an&quot;</td></tr><tr><td>-धा</td><td><ol><li>**Bei Zahladverbien in der Bedeutung &quot;-fach&quot;, &quot;-fältig&quot;<br>**z.B. द्विधा &quot;zweifach&quot;<br></li><li>**in der Bedeutung &quot;in der und der Weise&quot;<br>**z.B. समधा &quot;in gleicher Weise&quot; (zu सम 3 &quot;gleich&quot;)</li></ol></td></tr></tbody></table><h2 id="_37-5-adverbiale-komposita" tabindex="-1">37.5. Adverbiale Komposita <a class="header-anchor" href="#_37-5-adverbiale-komposita" aria-label="Permalink to &quot;37.5. Adverbiale Komposita&quot;">​</a></h2><h3 id="_37-5-1-komposita-mit-einem-adverb-oder-adverbial-gebrauchtem-kasus-als-hinterglied" tabindex="-1">37.5.1. Komposita mit einem Adverb oder adverbial gebrauchtem Kasus als Hinterglied <a class="header-anchor" href="#_37-5-1-komposita-mit-einem-adverb-oder-adverbial-gebrauchtem-kasus-als-hinterglied" aria-label="Permalink to &quot;37.5.1. Komposita mit einem Adverb oder adverbial gebrauchtem Kasus als Hinterglied&quot;">​</a></h3><p>Beispiel: सुचिरम् &quot;sehr lange (Zeit)&quot;</p><h3 id="_37-5-2-adverbial-gebrauchte-बहुव्रीहि" tabindex="-1">37.5.2. Adverbial gebrauchte बहुव्रीहि <a class="header-anchor" href="#_37-5-2-adverbial-gebrauchte-बहुव्रीहि" aria-label="Permalink to &quot;37.5.2. Adverbial gebrauchte बहुव्रीहि&quot;">​</a></h3><p>Beispiel: रक्षार्थम् &quot;in der Art von jemandem, dessen Zweck Behüten ist, zum Zweck des Behütens&quot;. Kann auch als zu 5.1. gehörig betrachtet werden: -अर्थम् als adverbiales Hinterglied.</p><h3 id="_37-5-3-अव्ययीभाव-komposita" tabindex="-1">37.5.3. अव्ययीभाव-Komposita <a class="header-anchor" href="#_37-5-3-अव्ययीभाव-komposita" aria-label="Permalink to &quot;37.5.3. अव्ययीभाव-Komposita&quot;">​</a></h3><p>अव्ययीभाव = &quot;unveränderlich/undeklinierbar gewordene&quot;</p><p>Ein अव्ययीभाव ist ein adverbiales Kompositum, dessen Vorderglied ein Indeklinabile (Postposition, Partikel u. ä.) ist, und dessen Hinterglied ein Nomen ist, das die Endung des Akkusativ Singulara Neutrum annnimmt.</p><p>Bei der Auflösung des Kompositums würde das Vorderglied das Hinterglied regieren:</p><p>Beispiele:</p><blockquote><p>प्रत्यग्नि = अग्निं प्रति = &quot;gegen das Feuer&quot;</p><p>यथाशक्ति = शक्तिमनतिक्रम्य = &quot;nach Kräften&quot;</p><p>अभिमुखम् = मुखम् अभि = &quot;nach vorn, entgegen&quot;</p></blockquote><p>Besonders wichtig sind अव्ययीभाव mit यथा &quot;wie&quot; als Vorderglied:</p><p>z.B. यथाकामम् = कामो यथास्ति = &quot;wie es der Wunsch ist, nach Wunsch, beliebig&quot;</p><p><img src="'+l+'" alt=""><br> Abb.: यथाशक्ति<br> [Bildquelle: Meanest Indian. -- <a href="http://www.flickr.com/photos/meanestindian/156516309/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/meanestindian/156516309/</a>. -- Zugriff am 2008-12-30. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_37-6-syntaktisches" tabindex="-1">37.6. Syntaktisches <a class="header-anchor" href="#_37-6-syntaktisches" aria-label="Permalink to &quot;37.6. Syntaktisches&quot;">​</a></h2><p>Bei den Verben</p><ul><li>अस् 2P &quot;sein&quot;</li><li>भू 1P</li><li>कृ 8U</li></ul><p>kann statt eines prädikativen Adjektivs ein prädikatives Adverb stehen:</p><p>z.B. तुष्णीं बभूव &quot;er wurde schweigend, er verstummte&quot;</p><p><img src="'+o+'" alt=""><br> Abb.: तुष्णीं बभूवुः<br> Chishti (چشتی) Dargah (درگه), Fatehpur Sikri = फतेहपूर सिकरी / فتحپور سیکری <br> [Bildquelle: Protocollide. -- <a href="http://www.flickr.com/photos/urbanvillage/1980227522/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/urbanvillage/1980227522/</a>. -- Zugriff am 2008-12-30. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_37-7-indefinitpronomina" tabindex="-1">37.7. Indefinitpronomina <a class="header-anchor" href="#_37-7-indefinitpronomina" aria-label="Permalink to &quot;37.7. Indefinitpronomina&quot;">​</a></h2><p>Indefinitpronomina (unbestimmte Fürwörter) werden durch Anfügen von</p><ul><li>-चिद्</li><li>-चन</li><li>अपि</li></ul><p>an die Kasus des Fragepronomens किम् gebildet.</p><p>z.B.</p><blockquote><p>कश्चिद् = कश्चन = को ऽपि = &quot;irgendeiner, irgendjemand&quot;<br> कस्यचिद् = irgendjemandes</p></blockquote><h2 id="_37-8-der-fragesatz" tabindex="-1">37.8. Der Fragesatz <a class="header-anchor" href="#_37-8-der-fragesatz" aria-label="Permalink to &quot;37.8. Der Fragesatz&quot;">​</a></h2><p>&quot;Wer?, wie?, was?, wieso? weshalb?, warum?<br> Wer nicht fragt bleibt dumm.&quot;</p><p>कः कथं किं<br> केन कस्मात्कस्मै ।<br> यो न पृच्छेन्<br> मूर्खस्तिष्ठेत् ॥</p><p>Motto der Sesamstraße, das eine gute Leitlinie fürs Leben und das Sanskritstudium ist</p><p>Siehe auch <a href="./lektion04">Lektion 4</a>.</p><p>Man muss unterscheiden</p><ul><li>Wortfragen (Ergänzungsfragen)</li><li>Satzfragen</li></ul><p>Bei Wortfragen wird nach einem Agens (कर्तृ), einem Objekt, einer Tätigkeit, einem Umstand ü. ä. gefragt, z.B.</p><ul><li>wer kommt?</li><li>was tut Rāma?</li><li>wen hört er?</li><li>wie spricht sie Sanskrit?</li><li>wo ist die Mutter?</li></ul><p>Bei Satzfragen wird der ganze Inhalt des Satzes erfragt, z.B.</p><ul><li>geht Rāma heute nach Ofterdingen?</li><li>ist es richtig, dass ... ?</li></ul><h3 id="_37-8-1-wortfragen-erganzungsfragen" tabindex="-1">37.8.1. Wortfragen (Ergänzungsfragen) <a class="header-anchor" href="#_37-8-1-wortfragen-erganzungsfragen" aria-label="Permalink to &quot;37.8.1. Wortfragen (Ergänzungsfragen)&quot;">​</a></h3><p>Schema:</p><p>Fragepronomen/Frageadverb - Satz</p><p>Beispiele:</p><blockquote><p>को ग्रामं गच्छति =  केन ग्रामो गम्यते = &quot;Wer geht ins Dorf?&quot;</p><p>किं बाला अधीयीरन् = &quot;Was sollten Kinder lernen?&quot;</p><p>क्व रामो वसति = Wo wohnt Rāma?</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: किं बाला अधीयीरन्<br> Kanchipuram = காஞ்சிபுரம<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/3103429189/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/3103429189/</a>. -- Zugriff am 2008-12-30. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><h3 id="_37-8-2-satzfragen" tabindex="-1">37.8.2. Satzfragen <a class="header-anchor" href="#_37-8-2-satzfragen" aria-label="Permalink to &quot;37.8.2. Satzfragen&quot;">​</a></h3><p>Manchmal ist es nur aus dem Zusammenhang erkennbar, ob ein Satz ein Fragesatz ist.</p><p>Schema I:</p><p>Verb - restlicher Satz</p><p>Beispiel:</p><blockquote><p>गमिष्यति ब्राह्मणबालो गुरुम् । &quot;Wird der Brahmanenjunge zu einem Meister gehen?&quot;</p></blockquote><p>Schema II:</p><p>Fragepartikel (meist am Satzanfang) - Satz</p><p>Die wichtigsten Fragpartikel sind:</p><ul><li><p>अपि</p></li><li><p>किम् (lässt oft eine negative Antwort erwarten)</p></li><li><p>कच्चिद्</p></li></ul><p>Diese Partikel entsprechen dem Fragezeichen.</p><p>Beispiel:</p><blockquote><p>अपि सत्यम् । &quot;Ist es auch wahr?&quot;</p><p>किं शक्नोति । &quot;Kann er denn?&quot;</p><p>कच्चित्क्षत्रियेण शत्रवो जिताः । &quot;Hat etwa der Kṣatriya die Feinde besiegt?&quot;</p></blockquote><p>Anmerkung: किम् kann außer &quot;was?&quot; und als Fragepartikel auch &quot;warum?, wozu?&quot; bedeuten. So bes. mit dem Instrumentalis (तृतीया):</p><blockquote><p>किं क्रोधेन । &quot;Wozu der Zorn? Was nützt der Zorn? Was soll der Zorn?&quot;</p></blockquote><h2 id="_37-9-wortliste" tabindex="-1">37.9. Wortliste <a class="header-anchor" href="#_37-9-wortliste" aria-label="Permalink to &quot;37.9. Wortliste&quot;">​</a></h2><p>मूर्ख 3: stumpfsinnig, blöd, dumm m. Dummkopf</p><p>मुनि m.: Weiser, (Schweige)asket</p><blockquote><p>शाक्यमुनि m.: Asket aus dem Geschlecht der शाक्य (Kṣatriyas aus कपिलवस्तु) = Buddha Gautama</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: शाक्यमुनिः<br> Hussain Sagar = హుస్సేన్ సాగర్, Hyderabad = హైదరాబాద్ <br> [Bildquelle: .krish.Tipirneni. -- <a href="http://www.flickr.com/photos/krish4u/426497125/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/krish4u/426497125/</a>. -- Zugriff am 2008-12-31. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>दिन n.: Tag</p><p>वृक्ष m.: Baum</p><p><img src="'+d+'" alt=""><br> Abb.: वृक्षः<br> जयपुर<br> [Bildquelle: counterclockwise. -- <a href="http://www.flickr.com/photos/xclockwise/520742595/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/xclockwise/520742595/</a>. -- Zugriff am 2008-12-31. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>मुख n.: Mund, Gesicht, Vorderteil, Anfang</p><h2 id="_37-10-ubung" tabindex="-1">37.10. Übung <a class="header-anchor" href="#_37-10-ubung" aria-label="Permalink to &quot;37.10. Übung&quot;">​</a></h2><p>A) Beantworten Sie folgende Fragen auf Sanskrit mit Hilfe der in Klammern angegebenen Wörter. Übersetzen Sie die Fragesätze.</p><p>Beispiel: क आगच्छति (राम) । » राम आगच्छति ।</p><p>कस्मै ब्राह्मण्यन्नं ददौ ॥१॥ (भिक्षु, बाला, दास, भगवन्त्)</p><p>क आर्यसत्यान्यजानात् ॥२॥ (बुद्ध, शाक्यमुनि)</p><p>कुत्राग्निश्चीयते ॥३॥ (यज्ञस्थान, मही)</p><p>कदा ब्राह्माणा घृतमग्नौ जुह्वति ॥४॥ (यज्ञकाल, देवान् स्तु &lt;Absolutiv&gt;)</p><p>कस्मान्मतिमतयः पुण्यं चक्रुः ॥५॥ (स्वर्गलोभ, नरकभय, भीतनरकता)</p><p>किमेव शस्त्रं छिनत्ति ॥६॥ (शरीर, अजीव)</p><p>किंकामः शत्रुरार्यैः सह युयुधे ॥७॥ (धनं जि)</p><p>कया भिक्षुरादितः ॥८॥ (गुणवती शूद्रा)</p><p>कुतः सुपुनर्भवं गम्यते ॥९॥ (कृतपुण्यत्व, सुनीति)</p><p>केन शूद्रा न काम्येत ॥१०॥ (द्विजाति, ब्राह्मण, साधु)</p><p>किमर्थं सुगतो ऽगारादनगार्यं प्रवव्राज ॥११॥ (दुःखमोक्ष, मोक्षनयन्ती प्रज्ञा)</p><p>कस्याः पुत्रः कृष्ण आसीत् ॥१२॥ (देवकी)</p><p><img src="'+h+'" alt=""><br> Abb.: कृष्ण und बलरा्म besuchen ihre Eltern वसुदेव und देवकी<br> Gemälde von राजा रवि वर्मा (1848 - 1906)<br> [Bildquelle: Wikipedia. Public domain]</p><p>क्व मर्तुं सज्जना इच्छन्ति ॥१३॥ (काशी = वाराणसी)</p><p><img src="'+p+'" alt=""><br> Abb.: क्व मर्तुं सज्जना इच्छन्ति<br> काशी = वाराणसी<br> [Bildquelle: amanderson2. -- <a href="http://www.flickr.com/photos/amanderson/2414520995/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/amanderson/2414520995/</a>. -- Zugriff am 2008-12-31. --  <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>केषां धर्मो वेदाध्ययनम् ॥१४॥ (द्विज, द्विजाति, आर्य)</p><p>कैर्वेदः प्रोक्तः ॥१५॥ (ऋषि)</p><p>कस्मिञ्जात आर्यः सुखमाप्नोति ॥१६॥ (पुत)</p><p>का नरा लुभ्यन्ति ॥१७॥ (सुरूपशरीरा, देवीरूपा)</p><p>के नराः सुरूपा लुभ्यन्ति ॥१८॥ (समोह, बुद्धिमन्त्)</p><p>कस्या इन्द्रः पुत्रं दास्यति ॥१९॥ (कृतव्रता पुण्यवती सुमतिब्राह्मणी)</p><p>B) Übersetzen Sie:</p><p>किं स्थितप्रज्ञः प्रव्रजेत्किमगारे पुत्रेषु वसेत् ॥१॥</p><p>अपि गुरुः सत्यं जानाति ॥२॥</p><p>कच्चिच्छुद्रा द्विजदासाः ॥३॥</p><p>कच्छिच्छुद्रो भारमाबिभः ॥४॥</p><p>C) Übersetzen Sie folgende अव्ययीभाव :</p><p>1. अति Postposition mit Akk.: &quot;über ... hinaus&quot;</p><ol><li>अतिमात्रम्</li><li>अतिवसन्तम्</li></ol><p>2. अधि &quot;in&quot;</p><ol><li>अधिहरि</li><li>अधिकेरलम्</li></ol><p><img src="'+m+'" alt=""><br> Abb.: अधिकेरलं वर्तन्ते<br> [Bildquelle: Michael Foley Photography. -- <a href="http://www.flickr.com/photos/michaelfoleyphotography/2388340875/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/michaelfoleyphotography/2388340875/</a>. -- Zugriff am 2008-12-31. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>3. अनु &quot;entsprechend, entlang, nach&quot;</p><ol><li>अनुरूपम्</li><li>अनुदिनम्</li><li>अनुगङ्गम्</li><li>अनुविष्णुम्</li></ol><p>4. अप &quot;ohne&quot;</p><ol><li>अपविष्णुम्</li></ol><p>5. अभि &quot;in Richtung auf&quot;</p><ol><li>अभिमुखम्</li><li>अभ्यग्नि</li></ol><p>6. आ &quot;seit, bis, einschließlich&quot;</p><ol><li>आबालवृद्धम्</li><li>आमरणम्</li></ol><p><img src="'+b+'" alt=""><br> Abb.: आबालवृद्धं लंदननगरे ववृतिरे<br> [Bildquelle: saketvora. -- <a href="http://www.flickr.com/photos/saket_vora/2676024863/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/saket_vora/2676024863/</a>. -- Zugriff am 2008-12-31. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>7. उप &quot;nahe&quot;</p><ol><li>उपवृक्षम्</li></ol><p><img src="'+c+'" alt=""><br> Abb.: उपवृक्षं सीदन्ति<br> Delhi = दहली / دہلی<br> [Bildquelle: Tianyake. -- <a href="http://www.flickr.com/photos/tianyake/1430877150/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/tianyake/1430877150/</a>. -- Zugriff am 2008-12-31. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>8. यथा</p><ol><li>यथास्थानम्</li></ol><h2 id="_37-11-wiederholungsubung" tabindex="-1">37.11. Wiederholungsübung <a class="header-anchor" href="#_37-11-wiederholungsubung" aria-label="Permalink to &quot;37.11. Wiederholungsübung&quot;">​</a></h2><p>Übersetzen Sie ins Sanskrit indem Sie ausschließlich Verbformen des Perfekt verwenden:</p><p>Als einmal irgendein Greis in ein anderes Dorf ging, ermüdete er unterwegs. Da ging er, um sich auszuruhen, zum Fuß eines an der Seite stehenden Mangobaums. Auf diesem Baum gab es reife Früchte. Der Greis bekam Lust auf diese. Aber er konnte nicht auf den Baum steigen und nach den Früchten greifen. Zum Glück waren auf diesem Baum irgendwelche Affen, die Früchte fraßen. Als er diese erblickte, freute sich der Greis. Was tat er? Er nahm einige Steine, zielte auf die Affen und warf. Die erbosten Affen pflückten irgendwelche Früchte und warfen sie auf den Greis. Der Greis nahm diese erfreut und ging in seine gewünschte Gegend. Siehe, das Geschick des Greises!</p>',168)])])}const B=t(g,[["render",k]]);export{A as __pageData,B as default};
